trait Container {
    fn add(&mut self, item: i32);
    fn get_len(&self) -> usize;
}

struct MyVec {
    data: Vec<i32>,
}

impl Container for MyVec {
    fn add(&mut self, item: i32) {
        let len = self.data.len();
        if len < 1000000000 { // Check before push
            self.data.push(item);
        }
    }
    fn get_len(&self) -> usize {
        self.data.len()
    }
}

fn main() {
    let mut vec = MyVec { data: Vec::new() };
    for i in 0..1_000_000_000 {
        vec.add(i);
    }
